  ('EMPSAN038', '2024-11-01'::date, 8600, 0, 29, 8600, 376, 0, 8224, (SELECT id FROM public.farms WHERE code='BPET1')),
  ('EMPRAK011', '2024-11-01'::date, 10000, 0, 29, 10000, 0, 0, 10000, (SELECT id FROM public.farms WHERE code='BPET1')),
  ('EMPBIS013', '2024-11-01'::date, 8600, 0, 29, 8600, 0, 0, 8600, (SELECT id FROM public.farms WHERE code='BPET1'))
) AS t(emp_id_str, pay_month, salary_base, increment, days_present,
       gross_amount, advance_deduction, tds_deduction, net_pay, farm_id)
JOIN public.employees e ON e.emp_id = t.emp_id_str
ON CONFLICT (employee_id, month) DO UPDATE SET
  days_worked = EXCLUDED.days_worked,
  earned_salary = EXCLUDED.earned_salary,
  advance = EXCLUDED.advance,
  tds = EXCLUDED.tds,
  net_salary = EXCLUDED.net_salary;
